 1	import React, { FC, Ref, useRef, useState } from 'react';
 2	
 3	import {
 4	  MenuToggleElement,
 5	  Select,
 6	  SelectList,
 7	  SelectOption,
 8	  SelectOptionProps,
 9	} from '@patternfly/react-core';
10	
11	import { NO_RESULTS_VALUE } from './constants';
12	import Toggle from './Toggle';
13	import { filterOptions } from './utils';
14	
15	type SelectMultiTypeaheadProps = {
16	  options: SelectOptionProps[];
17	  placeholder: string;
18	  selected: string[];
19	  setSelected: (newSelection: string[]) => void;
20	};
21	
22	const SelectMultiTypeahead: FC<SelectMultiTypeaheadProps> = ({
23	  options,
24	  placeholder,
25	  selected,
26	  setSelected,
27	}) => {
28	  const [isOpen, setIsOpen] = useState(false);
29	  const [inputValue, setInputValue] = useState<string>('');
30	  const [focusedItemIndex, setFocusedItemIndex] = useState<null | number>(null);
31	  const textInputRef = useRef<HTMLInputElement>();
32	
33	  const selectOptions = inputValue ? filterOptions(options, inputValue) : options;
34	
35	  const onSelect = (value: string) => {
36	    if (value && value !== NO_RESULTS_VALUE) {
37	      setSelected(
38	        selected?.includes(value)
39	          ? selected.filter((selection) => selection !== value)
40	          : [...(selected || []), value],
41	      );
42	
43	      setIsOpen(true);
44	    }
45	
46	    textInputRef.current?.focus();
47	  };
48	
49	  return (
50	    <Select
51	      id="multi-typeahead-select"
52	      isOpen={isOpen}
53	      onOpenChange={() => setIsOpen(false)}
54	      onSelect={(ev, selection) => onSelect(selection as string)}
55	      selected={selected}
56	      toggle={(toggleRef: Ref<MenuToggleElement>) => (
57	        <Toggle
58	          focusedItemIndex={focusedItemIndex}
59	          inputValue={inputValue}
60	          isOpen={isOpen}
61	          onSelect={onSelect}
62	          placeholder={placeholder}
63	          selected={selected}
64	          selectOptions={selectOptions}
65	          setFocusedItemIndex={setFocusedItemIndex}
66	          setInputValue={setInputValue}
67	          setIsOpen={setIsOpen}
68	          setSelected={setSelected}
69	          textInputRef={textInputRef}
70	          toggleRef={toggleRef}
71	        />
72	      )}
73	    >
74	      <SelectList id="select-multi-typeahead-listbox" isAriaMultiselectable>
75	        {selectOptions.map((option, index) => (
76	          <SelectOption
77	            className={option.className}
78	            id={`select-multi-typeahead-${option.value.replace(' ', '-')}`}
79	            isFocused={focusedItemIndex === index}
80	            key={option.value || option.children}
81	            {...option}
82	          >
83	            {option.children || option.value}
84	          </SelectOption>
85	        ))}
86	      </SelectList>
87	    </Select>
88	  );
89	};
90	
91	export default SelectMultiTypeahead;

